function merge(base,data){if(Array.isArray(base))return Array.isArray(data)?data:base;if(base&&typeof base==='object'){const out={...base};for(const k of Object.keys(base))out[k]=merge(base[k],data?.[k]);for(const k of Object.keys(data||{}))if(!(k in out))out[k]=data[k];return out}return data??base}
