function percent(done,total){return total?Math.round(done/total*100):0}
function bodyToday(){return state.body[todayKey()]||{}}
function missionCompleteness(){const fields=['identity','mission','motto','vision3','vision1','season'];const filled=fields.filter(k=>String(state.mission[k]||'').trim()).length;const valueScore=Math.min(state.values.length,4);const goalScore=Math.min(state.goals.length,4);return Math.round(((filled+valueScore+goalScore)/(fields.length+8))*100)}
function goalProgress(horizon){const goals=state.goals.filter(g=>!horizon||g.horizon===horizon);return goals.length?Math.round(goals.reduce((a,g)=>a+clamp(g.progress),0)/goals.length):0}
function alignment(){const big=percent(state.bigThree.filter(x=>x.done).length,Math.max(3,state.bigThree.length));const habits=percent(state.habits.filter(x=>x.done).length,state.habits.length);const routine=percent(state.routines.filter(x=>x.done).length,state.routines.length);const mission=missionCompleteness();const quarterly=goalProgress('Quarterly');const body=bodyToday();const bodyScore=Math.round(([body.steps>=10000,body.protein>=180,body.water>=100,Number(body.sleep)>=7,state.workout.done].filter(Boolean).length/5)*100);return Math.round(mission*.22+quarterly*.18+big*.25+habits*.15+routine*.08+bodyScore*.12)}
