function checkRow(x,bucket){return `<label class="check-row ${x.done?'done':''}"><input type="checkbox" data-toggle="${bucket}" data-id="${x.id}" ${x.done?'checked':''}><span>${esc(x.text)}</span><button type="button" class="icon-btn" data-delete="${bucket}" data-id="${x.id}">×</button></label>`}
