function projectCard(p){return `<article class="project-card"><div class="project-top"><div><strong>${esc(p.name)}</strong><small>${esc(p.next||'Define next action')}</small></div><button class="icon-btn" data-delete="projects" data-id="${p.id}">×</button></div><progress max="100" value="${clamp(p.progress)}"></progress><div class="project-meta"><small>${clamp(p.progress)}% complete</small><small>${esc(p.area||'Build')}</small></div></article>`}
function goalCard(g){return `<article class="goal-card"><strong>${esc(g.text)}</strong><small>${esc(g.area||'Mission')} · ${clamp(g.progress)}%</small><progress max="100" value="${clamp(g.progress)}"></progress><div class="goal-actions"><button class="mini-btn" data-edit-goal="${g.id}">Edit</button><button class="mini-btn" data-delete="goals" data-id="${g.id}">×</button></div></article>`}
function empty(t){return `<div class="list-card"><small>${esc(t)}</small></div>`}
function insight(){const score=alignment();if(!state.mission.mission)return'<strong>Define the mission before optimizing the day.</strong> Your operating system needs a clear source of truth.';const urgent=state.goals.filter(g=>g.horizon==='Quarterly').sort((a,b)=>a.progress-b.progress)[0];if(urgent&&clamp(urgent.progress)<35)return `<strong>Protect the quarterly objective:</strong> ${esc(urgent.text)} is only ${clamp(urgent.progress)}% complete.`;const undone=state.bigThree.find(x=>!x.done);if(undone)return `<strong>Next best action:</strong> ${esc(undone.text)}.`;const stale=state.projects.find(p=>clamp(p.progress)<100);if(stale)return `<strong>Advance a build:</strong> ${esc(stale.name)} needs one concrete next action.`;return score>=80?'<strong>The day is aligned.</strong> Finish cleanly and decide tomorrow before the day ends.':'<strong>Review your systems.</strong> Activity is not the same as alignment.'}
