function renderMission(){const mc=missionCompleteness();$('#missionCompleteness').textContent=`${mc}%`;for(const k of ['identity','mission','motto'])$(`#identityForm [name="${k}"]`).value=state.mission[k]||'';for(const k of ['vision3','vision1','season'])$(`#visionForm [name="${k}"]`).value=state.mission[k]||'';$('#valueList').innerHTML=state.values.map(v=>`<article class="value-card"><button class="mini-btn" data-delete="values" data-id="${v.id}">×</button><strong>${esc(v.name)}</strong><p>${esc(v.description)}</p></article>`).join('')||empty('Define the values that govern behavior.');$('#lifeAreaGrid').innerHTML=state.lifeAreas.map(a=>`<article class="life-area-card"><strong>${esc(a.name)}</strong><p>${esc(a.standard)}</p></article>`).join('');const horizons=['Annual','Quarterly','Monthly','Weekly'];$('#goalBoard').innerHTML=horizons.map(h=>{const items=state.goals.filter(g=>g.horizon===h);return `<section class="goal-column"><div class="goal-column-head"><strong>${h}</strong><span>${items.length}</span></div>${items.map(goalCard).join('')||`<small style="color:var(--muted)">No ${h.toLowerCase()} goals.</small>`}</section>`}).join('');const active=state.goals.filter(g=>clamp(g.progress)<100);$('#reviewHeadline').textContent=mc>=75?'Your mission has a clear center of gravity.':mc>=40?'Your direction is emerging.':'Your mission needs definition.';$('#reviewNarrative').textContent=active.length?`${active.length} active goals are competing for attention. The current quarter is ${goalProgress('Quarterly')}% complete.`:'Add goals to convert vision into measurable outcomes.';$('#missionReviewGrid').innerHTML=[['Mission clarity',`${mc}%`],['Quarter progress',`${goalProgress('Quarterly')}%`],['Active goals',active.length],['Core values',state.values.length],['Life areas',state.lifeAreas.length],['Reviews',state.missionReviews.length]].map(([a,b])=>`<article class="review-card"><span class="kicker">${esc(a)}</span><strong>${esc(b)}</strong></article>`).join('')}
function taskCard(t){const due=t.due||'';const overdue=due&&due<todayKey()&&!t.done;return `<article class="task-card ${t.done?'done':''} ${overdue?'overdue':''}"><label class="task-check"><input type="checkbox" data-task-toggle="${t.id}" ${t.done?'checked':''}><span></span></label><div class="grow"><div class="task-title-row"><strong>${esc(t.text)}</strong><span class="priority-badge ${esc((t.priority||'medium').toLowerCase())}">${esc(t.priority||'Medium')}</span></div><small>${due?`Due ${esc(due)}`:'No due date'}${t.area?` · ${esc(t.area)}`:''}</small>${t.note?`<p>${esc(t.note)}</p>`:''}</div><button class="icon-btn" data-delete="tasks" data-id="${t.id}">×</button></article>`}
