function timeBlockExecute(x){return `<div class="timeline-item ${x.done?'complete':''}"><span class="timeline-time">${esc(x.time)}</span><i class="timeline-dot"></i><div class="timeline-copy"><strong>${esc(x.title)}</strong><small>${esc(x.detail||'')}</small></div><label class="timeline-check"><input type="checkbox" data-time-toggle="${x.id}" ${x.done?'checked':''}><span>Done</span></label><button class="mini-btn" data-delete="timeBlocks" data-id="${x.id}">×</button></div>`}
function executionScore(){const big=percent(state.bigThree.filter(x=>x.done).length,Math.max(3,state.bigThree.length));const tasks=state.tasks.filter(t=>!t.due||t.due<=todayKey());const taskScore=percent(tasks.filter(t=>t.done).length,tasks.length);const habits=percent(state.habits.filter(x=>x.done).length,state.habits.length);const routines=percent(state.routines.filter(x=>x.done).length,state.routines.length);const blocks=percent(state.timeBlocks.filter(x=>x.done).length,state.timeBlocks.length);return Math.round(big*.35+taskScore*.20+habits*.18+routines*.12+blocks*.15)}
