function normalizeKnowledge(n){return {id:n.id||id(),type:n.type||'note',title:n.title||'Untitled',body:n.body||'',date:n.date||todayKey(),tags:n.tags||'',pinned:!!n.pinned,author:n.author||'',currentPage:num(n.currentPage),totalPages:num(n.totalPages),status:n.status||'Captured',rating:num(n.rating),application:n.application||'',updated:n.updated||n.date||todayKey(),...n}}
function knowledgeItems(){return state.notes.map(normalizeKnowledge)}
function knowledgeScore(){const items=knowledgeItems(),week=new Date(Date.now()-7*864e5).toISOString().slice(0,10),recent=items.filter(x=>x.date>=week).length,journals=items.filter(x=>x.type==='journal'&&x.date>=week).length,pages=state.readingSessions.filter(x=>x.date>=week).reduce((a,x)=>a+num(x.pages),0),reviews=state.knowledgeReviews.filter(x=>x.date>=week).length;return Math.min(100,recent*10+journals*15+Math.min(30,pages)+reviews*20)}
function knowledgeCard(n){const tags=String(n.tags||'').split(',').map(x=>x.trim()).filter(Boolean);return `<article class="knowledge-card ${n.pinned?'pinned':''}" data-open-knowledge="${n.id}"><div class="knowledge-card-top"><span class="type-pill">${esc(n.type)}</span><button class="pin-btn ${n.pinned?'active':''}" data-pin-knowledge="${n.id}" aria-label="Pin">${n.pinned?'◆':'◇'}</button></div><strong>${esc(n.title)}</strong><p>${esc(n.body).slice(0,220)}${String(n.body).length>220?'…':''}</p><div class="knowledge-tags">${tags.slice(0,4).map(t=>`<span>${esc(t)}</span>`).join('')}</div><div class="knowledge-meta"><small>${esc(n.date)}</small><button class="mini-btn" data-delete-knowledge="${n.id}">Delete</button></div></article>`}
function bookProgress(b){return b.totalPages?clamp(num(b.currentPage)/num(b.totalPages)*100):0}
function renderNotes(){state.notes=state.notes.map(normalizeKnowledge);const items=knowledgeItems(),score=knowledgeScore(),books=items.filter(x=>x.type==='book'),journals=items.filter(x=>x.type==='journal'),week=new Date(Date.now()-7*864e5).toISOString().slice(0,10),weekItems=items.filter(x=>x.date>=week);$('#knowledgeScore').textContent=`${score}%`;$('#knowledgeHeadline').textContent=score>=80?'You are learning with intention.':score>=50?'Keep converting inputs into action.':'Build your knowledge rhythm.';$('#knowledgeGuidance').textContent=weekItems.length?`You captured ${weekItems.length} item${weekItems.length===1?'':'s'} this week. Choose one to apply today.`:'Capture one useful idea, reflect on it, and decide where it belongs.';$('#knowledgeMetrics').innerHTML=[['Library',items.length],['This week',weekItems.length],['Journal',journals.length],['Books',books.length]].map(([k,v])=>`<div class="metric"><span>${k}</span><strong>${v}</strong></div>`).join('');$('#recentKnowledge').innerHTML=items.slice().sort((a,b)=>String(b.date).localeCompare(String(a.date))).slice(0,4).map(n=>`<div class="list-card"><div class="grow"><small>${esc(n.type)} · ${esc(n.date)}</small><strong>${esc(n.title)}</strong></div></div>`).join('')||empty('Capture your first lesson or idea.');const current=books.filter(b=>!['Complete','Abandoned'].includes(b.status)).slice(0,3);$('#currentBooks').innerHTML=current.map(b=>`<div class="list-card"><div class="grow"><small>${esc(b.author||'Unknown author')} · ${Math.round(bookProgress(b))}%</small><strong>${esc(b.title)}</strong><progress max="100" value="${bookProgress(b)}"></progress></div></div>`).join('')||empty('Add the book you are reading.');const tags={};items.forEach(n=>String(n.tags||'').split(',').map(x=>x.trim()).filter(Boolean).forEach(t=>tags[t]=(tags[t]||0)+1));$('#knowledgeMap').innerHTML=Object.entries(tags).sort((a,b)=>b[1]-a[1]).slice(0,20).map(([t,c])=>`<button data-tag-search="${esc(t)}">${esc(t)} <small>${c}</small></button>`).join('')||'<small>Add comma-separated tags to reveal connections.</small>';let filtered=items.filter(n=>knowledgeFilter==='all'||n.type===knowledgeFilter);if(knowledgeQuery)filtered=filtered.filter(n=>`${n.title} ${n.body} ${n.tags} ${n.author}`.toLowerCase().includes(knowledgeQuery));filtered.sort((a,b)=>(b.pinned-a.pinned)||String(b.updated||b.date).localeCompare(String(a.updated||a.date)));$('#noteList').innerHTML=filtered.map(knowledgeCard).join('')||empty('No captures match this view.');$('#journalPrompts').innerHTML=['What happened?','What did I learn?','What requires a decision?','What will I do differently?'].map(x=>`<button data-journal-prompt="${esc(x)}">${esc(x)}</button>`).join('');$('#journalList').innerHTML=journals.slice().sort((a,b)=>String(b.date).localeCompare(String(a.date))).map(n=>knowledgeCard(n)).join('')||empty('Your journal is ready for the first honest entry.');const pagesThisWeek=state.readingSessions.filter(x=>x.date>=week).reduce((a,x)=>a+num(x.pages),0);$('#readingMetrics').innerHTML=[['Reading',books.filter(x=>x.status==='Reading').length],['Completed',books.filter(x=>x.status==='Complete').length],['Pages this week',pagesThisWeek],['Sessions',state.readingSessions.length]].map(([k,v])=>`<div class="metric"><span>${k}</span><strong>${v}</strong></div>`).join('');$('#bookShelf').innerHTML=books.map(b=>`<article class="book-card"><div><span class="type-pill">${esc(b.status||'Reading')}</span><h3>${esc(b.title)}</h3><p>${esc(b.author||'Unknown author')}</p></div><div><div class="book-progress"><div><i style="width:${bookProgress(b)}%"></i></div><strong>${Math.round(bookProgress(b))}%</strong></div><small>Page ${num(b.currentPage)} of ${num(b.totalPages)||'—'}</small></div><p>${esc(b.application||b.body||'Capture the central lesson and how you will apply it.')}</p><div class="button-row"><button class="mini-btn" data-edit-book="${b.id}">Update</button><button class="mini-btn" data-delete-knowledge="${b.id}">Delete</button></div></article>`).join('')||empty('Add a book and retain more than the title.');$('#readingHistory').innerHTML=state.readingSessions.slice().sort((a,b)=>String(b.date).localeCompare(String(a.date))).slice(0,12).map(x=>`<div class="list-card"><div class="grow"><small>${esc(x.date)} · ${num(x.minutes)} min</small><strong>${esc(x.book)}</strong><p>${num(x.pages)} pages${x.note?' · '+esc(x.note):''}</p></div><button class="icon-btn" data-delete-reading="${x.id}">×</button></div>`).join('')||empty('No reading sessions logged.');$('#knowledgeReviewStats').innerHTML=[['Captures this week',weekItems.length],['Journal entries',journals.filter(x=>x.date>=week).length],['Pages read',pagesThisWeek],['Reviews saved',state.knowledgeReviews.length]].map(([k,v])=>`<article class="review-card"><span class="kicker">${k}</span><strong>${v}</strong></article>`).join('');$('#knowledgeReviewHistory').innerHTML=state.knowledgeReviews.slice().reverse().map(r=>`<div class="list-card"><div><small>${esc(r.date)}</small><strong>${esc(r.lesson)}</strong><p>${esc(r.application)}</p></div></div>`).join('')||empty('Complete the first weekly knowledge review.');bindKnowledgeDynamic()}
