 $$('[data-task-toggle]').forEach(el=>el.onchange=()=>{const t=state.tasks.find(x=>x.id===el.dataset.taskToggle);if(t){t.done=el.checked;t.completedAt=el.checked?new Date().toISOString():'';save()}});
 $$('[data-time-toggle]').forEach(el=>el.onchange=()=>{const t=state.timeBlocks.find(x=>x.id===el.dataset.timeToggle);if(t){t.done=el.checked;save()}});
