$('#startFocus').onclick=()=>{if(focusTimer){clearInterval(focusTimer);focusTimer=null;$('#startFocus span').textContent='Resume Focus';return}const mins=Number(state.execution.focusMinutes||25);if(!focusRemaining)focusRemaining=mins*60;$('#startFocus span').textContent='Pause';focusTimer=setInterval(()=>{focusRemaining--;const m=Math.floor(focusRemaining/60),sec=focusRemaining%60;$('#focusClock').textContent=`${String(m).padStart(2,'0')}:${String(sec).padStart(2,'0')}`;if(focusRemaining<=0){clearInterval(focusTimer);focusTimer=null;focusRemaining=0;state.focusSessions.push({id:id(),date:todayKey(),minutes:mins,label:$('#nextActionTitle').textContent});save();$('#focusClock').textContent=`${mins}:00`;$('#startFocus span').textContent='Start Focus';alert('Focus session complete.')}} ,1000)};



// Sprint 5 — Build System
let selectedProjectId=state.projects[0]?.id||null,projectFilter='active';
function normalizeProject(p){
  p.status=p.status||((clamp(p.progress)>=100)?'Complete':'Active');
  p.priority=p.priority||'Medium';p.description=p.description||'';p.owner=p.owner||'';p.startDate=p.startDate||'';p.dueDate=p.dueDate||'';
  p.budget=num(p.budget);p.tasks=Array.isArray(p.tasks)?p.tasks:[];p.expenses=Array.isArray(p.expenses)?p.expenses:[];p.shopping=Array.isArray(p.shopping)?p.shopping:[];p.measurements=Array.isArray(p.measurements)?p.measurements:[];p.milestones=Array.isArray(p.milestones)?p.milestones:[];p.projectNotes=Array.isArray(p.projectNotes)?p.projectNotes:[];
  return p;
}
state.projects.forEach(normalizeProject);state.version='1.0.0-sprint5';
function selectedProject(){if(!selectedProjectId&&state.projects.length)selectedProjectId=state.projects[0].id;return state.projects.find(p=>p.id===selectedProjectId)||null}
function money(v){return new Intl.NumberFormat(undefined,{style:'currency',currency:'USD',maximumFractionDigits:0}).format(num(v))}
function projectSpent(p){return p.expenses.reduce((a,x)=>a+num(x.amount),0)+p.shopping.filter(x=>x.bought).reduce((a,x)=>a+num(x.price)*Math.max(1,num(x.qty)),0)}
function projectTaskProgress(p){return p.tasks.length?percent(p.tasks.filter(x=>x.status==='Done').length,p.tasks.length):clamp(p.progress)}
function projectAttention(p){const overdue=p.dueDate&&p.dueDate<todayKey()&&p.status!=='Complete';const budget=p.budget>0&&projectSpent(p)>p.budget;const stale=!p.next||!p.tasks.some(x=>x.status!=='Done');return overdue||budget||stale}
function projectCard(p){normalizeProject(p);const spent=projectSpent(p),taskPct=projectTaskProgress(p),overdue=p.dueDate&&p.dueDate<todayKey()&&p.status!=='Complete';return `<article class="project-card enhanced" data-open-project="${p.id}"><div class="project-top"><div><div class="project-badges"><span class="status-pill">${esc(p.status)}</span><span class="priority-pill ${String(p.priority).toLowerCase()}">${esc(p.priority)}</span></div><strong>${esc(p.name)}</strong><small>${esc(p.next||'Define the next action')}</small></div><button class="icon-btn" data-delete-project="${p.id}" aria-label="Delete project">×</button></div><progress max="100" value="${taskPct}"></progress><div class="project-stats"><div class="project-stat"><strong>${taskPct}%</strong><small>Progress</small></div><div class="project-stat"><strong>${p.tasks.filter(x=>x.status!=='Done').length}</strong><small>Open tasks</small></div><div class="project-stat"><strong>${money(spent)}</strong><small>Spent</small></div></div><div class="project-meta"><small>${esc(p.area||'Build')}</small><small class="project-due ${overdue?'overdue':''}">${p.dueDate?(overdue?'Overdue · ':'Due · ')+esc(p.dueDate):'No due date'}</small></div></article>`}
function activateBuildTab(tab){$$('.build-tab').forEach(x=>x.classList.toggle('active',x.dataset.buildTab===tab));$$('.build-panel').forEach(x=>x.classList.toggle('active',x.dataset.buildPanel===tab));renderBuild()}
function projectSelector(){return state.projects.length?`<select class="project-selector" id="projectSelector">${state.projects.map(p=>`<option value="${p.id}" ${p.id===selectedProjectId?'selected':''}>${esc(p.name)}</option>`).join('')}</select>`:''}
function renderBuild(){
 state.projects.forEach(normalizeProject);const active=state.projects.filter(p=>p.status!=='Complete');const avg=state.projects.length?Math.round(state.projects.reduce((a,p)=>a+projectTaskProgress(p),0)/state.projects.length):0;const totalBudget=state.projects.reduce((a,p)=>a+num(p.budget),0),spent=state.projects.reduce((a,p)=>a+projectSpent(p),0);
 $('#buildScore').textContent=`${avg}%`;$('#buildMetrics').innerHTML=[['Active',active.length],['Needs attention',state.projects.filter(projectAttention).length],['Open tasks',state.projects.reduce((a,p)=>a+p.tasks.filter(x=>x.status!=='Done').length,0)],['Budget remaining',money(totalBudget-spent)]].map(([k,v])=>`<div class="metric"><span>${k}</span><strong>${v}</strong></div>`).join('');
 let list=state.projects;if(projectFilter==='active')list=list.filter(p=>p.status!=='Complete');if(projectFilter==='attention')list=list.filter(projectAttention);if(projectFilter==='complete')list=list.filter(p=>p.status==='Complete');$('#projectList').innerHTML=list.map(projectCard).join('')||empty('No projects match this view.');
 const p=selectedProject();renderProjectWorkspace(p);renderProjectKanban(p);renderProjectBudget(p);renderProjectPlan(p);bindBuildDynamic();
}
function renderProjectWorkspace(p){const el=$('#projectWorkspace');if(!p){el.innerHTML='<div class="workspace-empty"><strong>Create a project to open a workspace.</strong><p>Tasks, budget, shopping, measurements, milestones, and notes will stay connected here.</p></div>';return}const spent=projectSpent(p),remaining=num(p.budget)-spent,open=p.tasks.filter(x=>x.status!=='Done'),next=open.find(x=>x.status==='Doing')||open[0];el.innerHTML=`${projectSelector()}${projectAttention(p)?'<div class="attention-banner"><strong>Attention required.</strong> Check the next action, due date, or budget before this project drifts.</div>':''}<section class="workspace-hero"><div><div class="project-badges"><span class="status-pill">${esc(p.status)}</span><span class="priority-pill ${String(p.priority).toLowerCase()}">${esc(p.priority)}</span></div><h3>${esc(p.name)}</h3><p>${esc(p.description||'Define what done looks like and why this project matters.')}</p><small>${esc(p.area||'Build')} ${p.owner?'· Owner: '+esc(p.owner):''}</small></div><div class="workspace-actions"><button class="secondary-btn" data-edit-project="${p.id}">Edit</button><button class="primary-btn" data-complete-project="${p.id}">${p.status==='Complete'?'Reopen':'Complete'}</button></div></section><div class="workspace-grid"><article class="workspace-card"><span class="kicker">NEXT ACTION</span><div class="next-action-box"><strong>${esc(next?.text||p.next||'Define the next physical action')}</strong><p>${next?.due?'Due '+esc(next.due):'Make the next move specific enough to start immediately.'}</p></div></article><article class="workspace-card"><span class="kicker">CONTROL</span><div class="project-stats"><div class="project-stat"><strong>${projectTaskProgress(p)}%</strong><small>Done</small></div><div class="project-stat"><strong>${money(spent)}</strong><small>Spent</small></div><div class="project-stat"><strong>${money(remaining)}</strong><small>Remaining</small></div></div></article><article class="workspace-card"><h4>Finish Line</h4><p>${esc(p.finishLine||'Write the objective condition that proves this project is finished.')}</p><small>${p.dueDate?'Target: '+esc(p.dueDate):'No target date set'}</small></article><article class="workspace-card"><h4>Upcoming Milestones</h4>${p.milestones.filter(x=>!x.done).sort((a,b)=>String(a.date).localeCompare(String(b.date))).slice(0,3).map(x=>`<div class="list-card"><strong>${esc(x.name)}</strong><small>${esc(x.date||'No date')}</small></div>`).join('')||'<small>No milestones defined.</small>'}</article></div>`}
function renderProjectKanban(p){const el=$('#projectKanban');if(!p){el.innerHTML='<div class="workspace-empty">Select or create a project first.</div>';return}const cols=['Backlog','Doing','Done'];el.innerHTML=projectSelector()+`<div class="kanban-board">${cols.map(col=>{const tasks=p.tasks.filter(x=>x.status===col);return `<section class="kanban-column"><div class="kanban-head"><strong>${col}</strong><span>${tasks.length}</span></div><div class="kanban-list">${tasks.map(t=>`<article class="kanban-card"><div class="project-badges"><span class="priority-pill ${String(t.priority||'Medium').toLowerCase()}">${esc(t.priority||'Medium')}</span></div><strong>${esc(t.text)}</strong><p>${esc(t.note||'')}</p><small>${t.due?'Due '+esc(t.due):'No due date'}</small><div class="kanban-actions">${col!=='Backlog'?`<button class="mini-btn" data-move-task="${t.id}" data-direction="back">←</button>`:''}${col!=='Done'?`<button class="mini-btn" data-move-task="${t.id}" data-direction="forward">→</button>`:''}<button class="mini-btn" data-edit-project-task="${t.id}">Edit</button><button class="mini-btn" data-delete-project-task="${t.id}">×</button></div></article>`).join('')||'<small>No tasks.</small>'}</div></section>`}).join('')}</div>`}
function renderProjectBudget(p){const el=$('#projectBudget');if(!p){el.innerHTML='<div class="workspace-empty">Select or create a project first.</div>';return}const spent=projectSpent(p),remaining=num(p.budget)-spent;el.innerHTML=projectSelector()+`<article class="budget-card"><h3>Budget</h3><div class="budget-summary"><div class="budget-number"><small>Planned</small><strong>${money(p.budget)}</strong></div><div class="budget-number"><small>Spent</small><strong>${money(spent)}</strong></div><div class="budget-number ${remaining<0?'negative':''}"><small>Remaining</small><strong>${money(remaining)}</strong></div></div><div class="ledger">${p.expenses.map(x=>`<div class="ledger-row"><div><strong>${esc(x.name)}</strong><small>${esc(x.category||'Expense')} · ${esc(x.date||'')}</small></div><strong>${money(x.amount)}</strong><button class="mini-btn" data-delete-expense="${x.id}">×</button></div>`).join('')||'<small>No expenses logged.</small>'}</div></article><article class="budget-card"><h3>Shopping List</h3><div class="ledger">${p.shopping.map(x=>`<div class="shopping-row ${x.bought?'bought':''}"><input type="checkbox" data-shopping-toggle="${x.id}" ${x.bought?'checked':''}><div><strong>${esc(x.item)}</strong><small>${esc(x.store||'Any store')} · Qty ${esc(x.qty||1)}</small></div><strong>${money(num(x.price)*Math.max(1,num(x.qty)))}</strong><button class="mini-btn" data-delete-shopping="${x.id}">×</button></div>`).join('')||'<small>No shopping items.</small>'}</div></article>`}
function renderProjectPlan(p){const el=$('#projectPlan');if(!p){el.innerHTML='<div class="workspace-empty">Select or create a project first.</div>';return}el.innerHTML=projectSelector()+`<article class="plan-card"><h3>Measurements & Materials</h3><div class="measurement-list">${p.measurements.map(x=>`<div class="measurement-item"><div><strong>${esc(x.name)}</strong><small>${esc(x.note||'')}</small></div><strong>${esc(x.value)} ${esc(x.unit||'')}</strong></div>`).join('')||'<small>No measurements saved.</small>'}</div></article><article class="plan-card"><h3>Milestones</h3><div class="milestone-list">${p.milestones.sort((a,b)=>String(a.date).localeCompare(String(b.date))).map(x=>`<div class="milestone-item ${x.done?'done':''}"><input type="checkbox" data-milestone-toggle="${x.id}" ${x.done?'checked':''}><div><strong>${esc(x.name)}</strong><small>${esc(x.date||'No date')}</small></div><button class="mini-btn" data-delete-milestone="${x.id}">×</button></div>`).join('')||'<small>No milestones saved.</small>'}</div></article><article class="plan-card" style="grid-column:1/-1"><h3>Notes, Files & Links</h3><div class="project-note-list">${p.projectNotes.map(x=>`<div class="project-note-item"><strong>${esc(x.title)}</strong><p>${esc(x.note||'')}</p>${x.url?`<a href="${esc(x.url)}" target="_blank" rel="noopener">${esc(x.url)}</a>`:''}<button class="mini-btn" data-delete-project-note="${x.id}">Delete</button></div>`).join('')||'<small>No project notes or links.</small>'}</div></article>`}
function projectFields(p={}){return `<label>Project name<input name="name" required value="${esc(p.name||'')}"></label><label>Life area<input name="area" value="${esc(p.area||'')}" placeholder="Home, Family, Golf"></label><label>Status<select name="status">${['Active','On Hold','Complete'].map(x=>`<option ${p.status===x?'selected':''}>${x}</option>`).join('')}</select></label><label>Priority<select name="priority">${['High','Medium','Low'].map(x=>`<option ${p.priority===x?'selected':''}>${x}</option>`).join('')}</select></label><label>Owner<input name="owner" value="${esc(p.owner||'')}"></label><label>Due date<input name="dueDate" type="date" value="${esc(p.dueDate||'')}"></label><label>Budget<input name="budget" type="number" min="0" value="${num(p.budget)}"></label><label>Next action<input name="next" value="${esc(p.next||'')}"></label><label>Finish line<textarea name="finishLine">${esc(p.finishLine||'')}</textarea></label><label>Description<textarea name="description">${esc(p.description||'')}</textarea></label>`}
function openProjectTask(task={}){const p=selectedProject();if(!p)return alert('Create a project first.');openModal(task.id?'Edit Project Task':'New Project Task',`<label>Task<input name="text" required value="${esc(task.text||'')}"></label><label>Status<select name="status">${['Backlog','Doing','Done'].map(x=>`<option ${task.status===x?'selected':''}>${x}</option>`).join('')}</select></label><label>Priority<select name="priority">${['High','Medium','Low'].map(x=>`<option ${task.priority===x?'selected':''}>${x}</option>`).join('')}</select></label><label>Due date<input name="due" type="date" value="${esc(task.due||'')}"></label><label>Notes<textarea name="note">${esc(task.note||'')}</textarea></label>`,d=>{if(task.id)Object.assign(task,d);else p.tasks.push({id:id(),...d})})}
function bindBuildDynamic(){
 $$('[data-open-project]').forEach(x=>x.onclick=e=>{if(e.target.closest('[data-delete-project]'))return;selectedProjectId=x.dataset.openProject;activateBuildTab('workspace')});
 $$('[data-delete-project]').forEach(x=>x.onclick=e=>{e.stopPropagation();if(confirm('Delete this project and all connected data?')){state.projects=state.projects.filter(p=>p.id!==x.dataset.deleteProject);if(selectedProjectId===x.dataset.deleteProject)selectedProjectId=state.projects[0]?.id||null;save()}});
 $$('#projectSelector').forEach(x=>x.onchange=()=>{selectedProjectId=x.value;renderBuild()});
 $$('[data-edit-project]').forEach(x=>x.onclick=()=>{const p=state.projects.find(y=>y.id===x.dataset.editProject);openModal('Edit Project',projectFields(p),d=>Object.assign(p,d,{budget:num(d.budget)}))});
 $$('[data-complete-project]').forEach(x=>x.onclick=()=>{const p=state.projects.find(y=>y.id===x.dataset.completeProject);p.status=p.status==='Complete'?'Active':'Complete';p.progress=p.status==='Complete'?100:projectTaskProgress(p);save()});
 $$('[data-move-task]').forEach(x=>x.onclick=()=>{const p=selectedProject(),t=p.tasks.find(y=>y.id===x.dataset.moveTask),cols=['Backlog','Doing','Done'],i=cols.indexOf(t.status);t.status=cols[Math.max(0,Math.min(2,i+(x.dataset.direction==='forward'?1:-1)))];p.progress=projectTaskProgress(p);save()});
 $$('[data-edit-project-task]').forEach(x=>x.onclick=()=>openProjectTask(selectedProject().tasks.find(t=>t.id===x.dataset.editProjectTask)));
 $$('[data-delete-project-task]').forEach(x=>x.onclick=()=>{const p=selectedProject();p.tasks=p.tasks.filter(t=>t.id!==x.dataset.deleteProjectTask);save()});
 $$('[data-shopping-toggle]').forEach(x=>x.onchange=()=>{selectedProject().shopping.find(y=>y.id===x.dataset.shoppingToggle).bought=x.checked;save()});
 $$('[data-milestone-toggle]').forEach(x=>x.onchange=()=>{selectedProject().milestones.find(y=>y.id===x.dataset.milestoneToggle).done=x.checked;save()});
 [['expense','expenses'],['shopping','shopping'],['milestone','milestones'],['project-note','projectNotes']].forEach(([attr,key])=>$$(`[data-delete-${attr}]`).forEach(x=>x.onclick=()=>{const p=selectedProject();p[key]=p[key].filter(y=>y.id!==x.dataset[`delete${attr.split('-').map(z=>z[0].toUpperCase()+z.slice(1)).join('')}`]);save()}));
}
$$('.build-tab').forEach(t=>t.onclick=()=>activateBuildTab(t.dataset.buildTab));
$$('[data-project-filter]').forEach(c=>c.onclick=()=>{$$('[data-project-filter]').forEach(x=>x.classList.remove('active'));c.classList.add('active');projectFilter=c.dataset.projectFilter;renderBuild()});
$('#addProject').onclick=()=>openModal('New Project',projectFields({status:'Active',priority:'Medium'}),d=>{const p=normalizeProject({id:id(),...d,budget:num(d.budget),progress:0});state.projects.push(p);selectedProjectId=p.id});
$('#addProjectTask').onclick=()=>openProjectTask();
$('#addExpense').onclick=()=>{const p=selectedProject();if(!p)return alert('Create a project first.');openModal('Add Expense','<label>Description<input name="name" required></label><label>Amount<input name="amount" type="number" step=".01" required></label><label>Category<input name="category" placeholder="Materials, labor, tools"></label><label>Date<input name="date" type="date" value="'+todayKey()+'"></label>',d=>p.expenses.push({id:id(),...d,amount:num(d.amount)}))};
$('#addShoppingItem').onclick=()=>{const p=selectedProject();if(!p)return alert('Create a project first.');openModal('Add Shopping Item','<label>Item<input name="item" required></label><label>Quantity<input name="qty" type="number" min="1" value="1"></label><label>Estimated price each<input name="price" type="number" step=".01" value="0"></label><label>Store<input name="store"></label>',d=>p.shopping.push({id:id(),...d,qty:num(d.qty)||1,price:num(d.price),bought:false}))};
$('#addMeasurement').onclick=()=>{const p=selectedProject();if(!p)return alert('Create a project first.');openModal('Add Measurement','<label>Name<input name="name" required placeholder="Lid length"></label><label>Value<input name="value" required></label><label>Unit<input name="unit" placeholder="in, ft, sq ft"></label><label>Notes<input name="note"></label>',d=>p.measurements.push({id:id(),...d}))};
$('#addMilestone').onclick=()=>{const p=selectedProject();if(!p)return alert('Create a project first.');openModal('Add Milestone','<label>Milestone<input name="name" required></label><label>Target date<input name="date" type="date"></label>',d=>p.milestones.push({id:id(),...d,done:false}))};
$('#addProjectNote').onclick=()=>{const p=selectedProject();if(!p)return alert('Create a project first.');openModal('Add Note or Link','<label>Title<input name="title" required></label><label>Note<textarea name="note"></textarea></label><label>Link<input name="url" type="url" placeholder="https://"></label>',d=>p.projectNotes.push({id:id(),...d,date:todayKey()}))};


function intelligenceSystemScores(){
 const b=bodyToday(), projectScores=state.projects.map(projectTaskProgress), recent=new Date(Date.now()-7*864e5).toISOString().slice(0,10);
 return {
  Mission:Math.round((missionCompleteness()+goalProgress('Quarterly'))/2),
  Execute:Math.round((percent(state.bigThree.filter(x=>x.done).length,Math.max(3,state.bigThree.length))+percent(state.habits.filter(x=>x.done).length,state.habits.length)+percent(state.tasks.filter(x=>x.done).length,state.tasks.length))/3),
  Body:Math.round((bodyReadiness(b)+bodyDayScore(b))/2),
  Build:projectScores.length?Math.round(projectScores.reduce((a,x)=>a+x,0)/projectScores.length):0,
  Learn:knowledgeScore(),
  Review:Math.min(100,(state.reviews.filter(x=>x.date>=recent).length*20)+(state.weeklyReviews.some(x=>x.date>=recent)?40:0))
 };
}
function daysBetween(a,b=todayKey()){if(!a)return 999;return Math.max(0,Math.floor((new Date(b)-new Date(a))/864e5))}
function intelligenceSignals(){
 const out=[], b=bodyToday(), today=todayKey(), scores=intelligenceSystemScores();
 const add=(key,severity,title,detail,system,navTarget,action)=>out.push({key,severity,title,detail,system,navTarget,action});
 if(!state.mission.mission)add('mission-missing','high','Define the source of truth','Your daily choices cannot be evaluated against a mission until the mission statement is defined.','Mission','mission','Write mission');
 const lowQuarter=state.goals.filter(g=>g.horizon==='Quarterly'&&clamp(g.progress)<40).sort((a,b)=>a.progress-b.progress)[0];
 if(lowQuarter)add('quarter-'+lowQuarter.id,'high','Quarterly objective is underprotected',`${lowQuarter.text} is at ${clamp(lowQuarter.progress)}%. Put a concrete supporting action into today’s Big Three.`,'Mission','mission','Review goal');
 const undone=state.bigThree.filter(x=>!x.done);if(undone.length)add('big-three','high','Finish the defining outcomes',`${undone.length} of today’s Big Three remain open. Complete “${undone[0].text}” before expanding the field.`,'Execute','execute','Execute now');
 const overdue=state.tasks.filter(t=>!t.done&&t.due&&t.due<today);if(overdue.length)add('overdue-tasks','high','Overdue work is accumulating',`${overdue.length} task${overdue.length===1?' is':'s are'} overdue. Renegotiate, complete, or delete each one.`,'Execute','execute','Triage tasks');
 const stalled=state.projects.filter(p=>p.status!=='Complete'&&projectTaskProgress(p)<100&&daysBetween(p.updated||p.created||p.date)>7);if(stalled.length)add('stalled-projects','medium','A meaningful build has gone stale',`${stalled[0].name} has no recent activity. Define one physical next action or place it on hold.`,'Build','build','Open project');
 const overBudget=state.projects.filter(p=>num(p.budget)>0&&projectSpent(p)>num(p.budget));if(overBudget.length)add('budget-risk','high','Project budget exceeded',`${overBudget[0].name} is ${money(projectSpent(overBudget[0])-num(overBudget[0].budget))} over budget.`,'Build','build','Review budget');
 if(num(b.sleep)>0&&num(b.sleep)<6.5)add('sleep-low','high','Recovery is constraining performance',`${b.sleep} hours of sleep is below your ${state.bodyGoals.sleep}-hour target. Reduce training intensity and protect tonight’s shutdown.`,'Body','body','Review recovery');
 if(num(b.protein)>0&&num(b.protein)<num(state.bodyGoals.protein)*.7)add('protein-low','medium','Protein intake is behind',`${b.protein} g logged against a ${state.bodyGoals.protein} g target. Close the gap before discretionary calories.`,'Body','body','Log nutrition');
 if(!num(b.sleep)&&!num(b.energy))add('body-unlogged','low','Body signals are missing','Log sleep, energy, soreness, and stress so training guidance reflects actual readiness.','Body','body','Log recovery');
 const week=new Date(Date.now()-7*864e5).toISOString().slice(0,10), recentKnowledge=knowledgeItems().filter(x=>x.date>=week);if(!recentKnowledge.length)add('knowledge-empty','low','Capture what this week taught you','No knowledge has been retained in the last seven days. Save one lesson and how you will apply it.','Learn','knowledge','Capture lesson');
 if(!state.weeklyReviews.some(x=>x.date>=week))add('weekly-review','medium','Close the weekly feedback loop','No weekly execution review is recorded in the last seven days. Review evidence before planning the next week.','Execute','execute','Start review');
 const dismissed=state.intelligence?.dismissed||{};return out.filter(x=>dismissed[x.key]!==today).sort((a,b)=>({high:0,medium:1,low:2}[a.severity]-{high:0,medium:1,low:2}[b.severity]));
}
function intelligenceConnections(){const c=[];const quarterly=state.goals.filter(g=>g.horizon==='Quarterly');const projects=state.projects.filter(p=>p.status!=='Complete');if(quarterly.length&&projects.length)c.push({title:'Mission → Build',detail:`${projects.length} active project${projects.length===1?'':'s'} should visibly support ${quarterly.length} quarterly objective${quarterly.length===1?'':'s'}. Verify each project’s life area and finish line.`});const b=bodyToday();if(num(b.sleep)&&state.workouts.some(w=>w.date===todayKey()))c.push({title:'Recovery → Training',detail:`Today’s ${b.sleep}-hour sleep input is being considered alongside the planned workout and readiness score.`});if(state.notes.length&&state.tasks.length)c.push({title:'Knowledge → Execution',detail:`You have ${state.notes.length} knowledge captures and ${state.tasks.filter(t=>!t.done).length} open tasks. Convert useful lessons into explicit next actions.`});if(state.projects.some(p=>p.shopping?.length))c.push({title:'Build → Budget',detail:'Shopping purchases and expenses are connected to project budget risk, not treated as isolated lists.'});return c}
function renderIntelligence(){
 if(!$('#intelligenceScore'))return;state.intelligence=state.intelligence||{dismissed:{},history:[],lastBrief:''};const scores=intelligenceSystemScores(),vals=Object.values(scores),health=Math.round(vals.reduce((a,x)=>a+x,0)/vals.length),signals=intelligenceSignals(),connections=intelligenceConnections();
 $('#intelligenceScore').textContent=`${health}%`;$('#briefHeadline').textContent=signals[0]?.title||(health>=80?'Your systems are moving together.':'The system is stable. Protect the next meaningful action.');$('#briefNarrative').textContent=signals[0]?.detail||`Overall system health is ${health}%. No critical contradiction is currently detected.`;$('#priorityCount').textContent=`${signals.length} active`;
 $('#systemHealthGrid').innerHTML=Object.entries(scores).map(([name,score])=>`<article class="health-tile"><div><span>${esc(name)}</span><strong>${score}%</strong></div><progress max="100" value="${score}"></progress></article>`).join('');
 $('#intelligenceQueue').innerHTML=signals.map(x=>`<article class="intel-card ${x.severity}"><div class="intel-card-head"><div><span class="kicker">${esc(x.system)}</span><h4>${esc(x.title)}</h4></div><span class="intel-severity">${esc(x.severity)}</span></div><p>${esc(x.detail)}</p><div class="intel-actions"><button class="primary-btn small" data-intel-action="${esc(x.key)}" data-intel-nav="${esc(x.navTarget)}">${esc(x.action)}</button><button class="mini-btn" data-intel-dismiss="${esc(x.key)}">Dismiss today</button></div></article>`).join('')||empty('No active warnings. Keep executing the plan and close the day with a review.');
 $('#connectionList').innerHTML=connections.map(x=>`<article class="connection-card"><strong>${esc(x.title)}</strong><small>${esc(x.detail)}</small></article>`).join('')||empty('Connections appear as each system gains data.');
 const week=new Date(Date.now()-7*864e5).toISOString().slice(0,10),completed=state.tasks.filter(t=>t.done).length,focus=state.focusSessions.filter(x=>x.date>=week).reduce((a,x)=>a+num(x.minutes),0),pages=state.readingSessions.filter(x=>x.date>=week).reduce((a,x)=>a+num(x.pages),0),projectAvg=state.projects.length?Math.round(state.projects.reduce((a,p)=>a+projectTaskProgress(p),0)/state.projects.length):0;
 $('#patternGrid').innerHTML=[[completed,'Tasks completed','Execution evidence'],[focus+' min','Focused this week',focus>=100?'Positive momentum':'Needs protection'],[pages,'Pages read this week','Knowledge input'],[projectAvg+'%','Average project progress','Build portfolio'],[bodyReadiness(b),'Readiness today','Body signal'],[alignment()+'%','Alignment today','Whole system']].map(([v,k,d])=>`<article class="review-card"><span class="kicker">${esc(k)}</span><strong>${esc(v)}</strong><small>${esc(d)}</small></article>`).join('');
 $('#intelligenceHistory').innerHTML=(state.intelligence.history||[]).slice().reverse().slice(0,12).map(x=>`<div class="list-card"><div><small>${esc(x.date)} · ${esc(x.system)}</small><strong>${esc(x.title)}</strong><p>${esc(x.result)}</p></div></div>`).join('')||empty('Actions taken from recommendations will appear here.');bindIntelligenceDynamic();
}
function bindIntelligenceDynamic(){
 $$('[data-intel-dismiss]').forEach(b=>b.onclick=()=>{state.intelligence.dismissed[b.dataset.intelDismiss]=todayKey();save()});
 $$('[data-intel-action]').forEach(b=>b.onclick=()=>{const signal=intelligenceSignals().find(x=>x.key===b.dataset.intelAction);if(signal){state.intelligence.history.push({id:id(),date:todayKey(),system:signal.system,title:signal.title,result:'Recommendation opened'});state.intelligence.dismissed[signal.key]=todayKey();localStorage.setItem(KEY,JSON.stringify(state));nav(b.dataset.intelNav);render()}});
}
$('#refreshIntelligence').onclick=()=>{state.intelligence.lastBrief=new Date().toISOString();save()};$('#clearIntelHistory').onclick=()=>{if(confirm('Clear intelligence decision history?')){state.intelligence.history=[];save()}};

if('serviceWorker'in navigator)addEventListener('load',()=>navigator.serviceWorker.register('./service-worker.js').catch(()=>{}));render();nav(location.hash.slice(1)||'today',{replace:true});
